import{_ as t,o as i,c as a,an as n}from"./chunks/framework.DKgvuBLA.js";const u=JSON.parse('{"title":"API Reference","description":"TypeScript API reference for tsParticles — engine, options, container, plugins, and typedoc-generated documentation.","frontmatter":{"title":"API Reference","description":"TypeScript API reference for tsParticles — engine, options, container, plugins, and typedoc-generated documentation."},"headers":[],"relativePath":"api/index.md","filePath":"api/index.md"}'),r={name:"api/index.md"};function o(s,e,d,c,l,p){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="api-reference" tabindex="-1">API Reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API Reference&quot;">​</a></h1><p>The tsParticles API is organized into layers. Use this page to find the right section.</p><h2 id="quick-links" tabindex="-1">Quick Links <a class="header-anchor" href="#quick-links" aria-label="Permalink to &quot;Quick Links&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Section</th><th>Description</th></tr></thead><tbody><tr><td><a href="/docs/">Full API docs (typedoc)</a></td><td>Auto-generated reference for all packages</td></tr><tr><td><a href="/docs/modules/tsParticles_Engine.html">Engine</a></td><td>Core engine — <code>Engine</code>, <code>Container</code>, <code>tsParticles</code> instance</td></tr><tr><td><a href="/docs/interfaces/tsParticles_Engine.Options_Interfaces_IOptions.IOptions.html">Options</a></td><td>Complete options interface tree</td></tr><tr><td><a href="/docs/classes/tsParticles_Engine.Core_Container.Container.html">Container</a></td><td>Runtime container — play, pause, refresh, export</td></tr><tr><td><a href="/docs/modules/Core_Interfaces_IPlugin.html">IPlugin</a></td><td>Plugin interface for custom extensions</td></tr></tbody></table><h2 id="engine" tabindex="-1">Engine <a class="header-anchor" href="#engine" aria-label="Permalink to &quot;Engine&quot;">​</a></h2><p>The <code>@tsparticles/engine</code> package exports the core classes:</p><ul><li><strong><code>tsParticles</code></strong> — global singleton instance</li><li><strong><code>Engine</code></strong> — the engine class used to create and manage containers</li><li><strong><code>Container</code></strong> — a single particle canvas instance</li><li><strong><code>load</code></strong> — the main entry point for creating particles</li></ul><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h2><p>The options object is a plain TypeScript interface. Key nested types:</p><ul><li><code>IOptions</code> — root options (background, particles, interactivity, plugins)</li><li><code>IParticlesOptions</code> — per-particle options (move, shape, size, color, etc.)</li><li><code>IInteractivity</code> — click, hover, and scroll events + modes</li></ul><p>Browse the <a href="/options/">Options Reference</a> or the full <a href="/docs/interfaces/tsParticles_Engine.Options_Interfaces_IOptions.IOptions.html">Options type</a>.</p><h2 id="container-api" tabindex="-1">Container API <a class="header-anchor" href="#container-api" aria-label="Permalink to &quot;Container API&quot;">​</a></h2><p>The <code>Container</code> class controls a running particle instance:</p><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>play()</code></td><td>Resume animation</td></tr><tr><td><code>pause()</code></td><td>Stop animation</td></tr><tr><td><code>refresh()</code></td><td>Destroy and re-create particles with current options</td></tr><tr><td><code>export(type)</code></td><td>Export current frame as image/canvas blob</td></tr><tr><td><code>addListener(event, cb)</code></td><td>Subscribe to container events</td></tr></tbody></table><h2 id="plugin-system" tabindex="-1">Plugin System <a class="header-anchor" href="#plugin-system" aria-label="Permalink to &quot;Plugin System&quot;">​</a></h2><p>tsParticles supports custom plugins, shapes, updaters, interactions, and paths.</p><ul><li><a href="/guide/plugins-customization-plugin">Plugin guide</a></li><li><a href="/guide/plugins-customization-shape">Shape guide</a></li><li><a href="/guide/plugins-customization-updater">Updater guide</a></li><li><a href="/guide/plugins-customization-interaction">Interaction guide</a></li><li><a href="/docs/modules/Core_Interfaces_IPlugin.html">IPlugin typedoc</a></li></ul><h2 id="bundles" tabindex="-1">Bundles <a class="header-anchor" href="#bundles" aria-label="Permalink to &quot;Bundles&quot;">​</a></h2><p>Choose the right import for your project:</p><table tabindex="0"><thead><tr><th>Bundle</th><th>Included</th></tr></thead><tbody><tr><td><code>@tsparticles/basic</code></td><td>Core + circle shape + color + size + opacity + move</td></tr><tr><td><code>@tsparticles/slim</code></td><td>Basic + interactivity + polygons + images + emoji + stars</td></tr><tr><td><code>tsparticles</code> (full)</td><td>Slim + absorbers + emitters + trail + sounds + all shapes</td></tr><tr><td><code>@tsparticles/all</code></td><td>Everything including ships + fireworks + confetti</td></tr></tbody></table><p>Package-level <a href="/guide/dependency-graph">Dependency Graph</a>.</p><h2 id="migration-versioning" tabindex="-1">Migration &amp; Versioning <a class="header-anchor" href="#migration-versioning" aria-label="Permalink to &quot;Migration &amp; Versioning&quot;">​</a></h2><ul><li><a href="/migrations/">Migration overview</a></li><li><a href="/migrations/changelog">Changelog</a></li><li><a href="/migrations/releases">Releases</a></li></ul>',23)])])}const g=t(r,[["render",o]]);export{u as __pageData,g as default};
